import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

const SeatSelection = () => {
  const [selectedBus, setSelectedBus] = useState(null);
  const [selectedSeats, setSelectedSeats] = useState([]);
  const [seatLayout, setSeatLayout] = useState([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    const storedBus = localStorage.getItem('selectedBus');
    if (storedBus) {
      const bus = JSON.parse(storedBus);
      setSelectedBus(bus);
      generateSeatLayout(bus);
    } else {
      navigate('/buses');
    }
  }, [navigate]);

  const generateSeatLayout = (bus) => {
    setLoading(true);
    const rows = 10;
    const seatsPerRow = 4;
    const layout = [];
    
    // Generate some random booked seats for demo
    const bookedSeats = new Set();
    const totalSeats = bus.totalSeats;
    const bookedCount = totalSeats - bus.availableSeats;
    
    while (bookedSeats.size < bookedCount) {
      bookedSeats.add(Math.floor(Math.random() * totalSeats) + 1);
    }

    for (let row = 0; row < rows; row++) {
      const rowSeats = [];
      for (let col = 0; col < seatsPerRow; col++) {
        const seatNumber = row * seatsPerRow + col + 1;
        if (seatNumber > totalSeats) break;
        
        rowSeats.push({
          number: seatNumber,
          isBooked: bookedSeats.has(seatNumber),
          row: row + 1,
          position: col < 2 ? 'left' : 'right'
        });
      }
      if (rowSeats.length > 0) {
        layout.push(rowSeats);
      }
    }

    setTimeout(() => {
      setSeatLayout(layout);
      setLoading(false);
    }, 500);
  };

  const handleSeatClick = (seat) => {
    if (seat.isBooked) return;

    setSelectedSeats(prev => {
      const isSelected = prev.some(s => s.number === seat.number);
      if (isSelected) {
        return prev.filter(s => s.number !== seat.number);
      } else {
        return [...prev, seat];
      }
    });
  };

  const getTotalPrice = () => {
    return selectedSeats.length * (selectedBus?.price || 0);
  };

  const handleProceed = () => {
    if (selectedSeats.length === 0) {
      alert('Please select at least one seat');
      return;
    }

    const bookingData = {
      bus: selectedBus,
      seats: selectedSeats,
      totalPrice: getTotalPrice(),
      bookingId: 'BK' + Date.now(),
      timestamp: new Date().toISOString()
    };

    localStorage.setItem('bookingData', JSON.stringify(bookingData));
    navigate('/payment');
  };

  const handleBack = () => {
    navigate('/buses');
  };

  if (loading) {
    return (
      <div className="card" style={{ textAlign: 'center', padding: '50px' }}>
        <p>Loading seat layout...</p>
      </div>
    );
  }

  return (
    <div className="card">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
        <h2>Select Seats</h2>
        <button className="btn btn-secondary" onClick={handleBack}>
          ← Back to Buses
        </button>
      </div>

      {selectedBus && (
        <div style={{ background: '#f8f9fa', padding: '15px', borderRadius: '5px', marginBottom: '20px' }}>
          <h3>{selectedBus.busName}</h3>
          <p>{selectedBus.busType} | {selectedBus.departure} - {selectedBus.arrival}</p>
        </div>
      )}

      <div style={{ marginBottom: '30px' }}>
        <h4>Seat Layout</h4>
        
        <div style={{ display: 'flex', justifyContent: 'center', gap: '30px', marginBottom: '20px' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
            <div style={{ width: '20px', height: '20px', backgroundColor: '#28a745', border: '1px solid #ddd' }}></div>
            <span>Available</span>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
            <div style={{ width: '20px', height: '20px', backgroundColor: '#007bff', border: '1px solid #ddd' }}></div>
            <span>Selected</span>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
            <div style={{ width: '20px', height: '20px', backgroundColor: '#dc3545', border: '1px solid #ddd' }}></div>
            <span>Booked</span>
          </div>
        </div>

        <div style={{ textAlign: 'center', marginBottom: '20px' }}>
          <div style={{ 
            background: '#333', 
            color: 'white', 
            padding: '10px', 
            borderRadius: '5px',
            marginBottom: '30px'
          }}>
            DRIVER
          </div>
        </div>

        <div style={{ display: 'flex', flexDirection: 'column', gap: '10px', alignItems: 'center' }}>
          {seatLayout.map((row, rowIndex) => (
            <div key={rowIndex} style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
              <div style={{ width: '30px', textAlign: 'center', fontWeight: 'bold' }}>
                {rowIndex + 1}
              </div>
              
              <div style={{ display: 'flex', gap: '5px' }}>
                {row.slice(0, 2).map((seat) => (
                  <button
                    key={seat.number}
                    onClick={() => handleSeatClick(seat)}
                    disabled={seat.isBooked}
                    style={{
                      width: '35px',
                      height: '35px',
                      border: '1px solid #ddd',
                      borderRadius: '4px',
                      cursor: seat.isBooked ? 'not-allowed' : 'pointer',
                      backgroundColor: seat.isBooked 
                        ? '#dc3545' 
                        : selectedSeats.some(s => s.number === seat.number)
                          ? '#007bff'
                          : '#28a745',
                      color: 'white',
                      fontSize: '12px',
                      fontWeight: 'bold'
                    }}
                  >
                    {seat.number}
                  </button>
                ))}
              </div>

              <div style={{ width: '20px' }}></div>

              <div style={{ display: 'flex', gap: '5px' }}>
                {row.slice(2).map((seat) => (
                  <button
                    key={seat.number}
                    onClick={() => handleSeatClick(seat)}
                    disabled={seat.isBooked}
                    style={{
                      width: '35px',
                      height: '35px',
                      border: '1px solid #ddd',
                      borderRadius: '4px',
                      cursor: seat.isBooked ? 'not-allowed' : 'pointer',
                      backgroundColor: seat.isBooked 
                        ? '#dc3545' 
                        : selectedSeats.some(s => s.number === seat.number)
                          ? '#007bff'
                          : '#28a745',
                      color: 'white',
                      fontSize: '12px',
                      fontWeight: 'bold'
                    }}
                  >
                    {seat.number}
                  </button>
                ))}
              </div>

              <div style={{ width: '30px' }}></div>
            </div>
          ))}
        </div>
      </div>

      <div style={{ borderTop: '1px solid #ddd', paddingTop: '20px' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div>
            <h4>Booking Summary</h4>
            <p>Selected Seats: {selectedSeats.map(s => s.number).join(', ') || 'None'}</p>
            <p><strong>Total Price: ₹{getTotalPrice()}</strong></p>
          </div>
          <button 
            className="btn" 
            onClick={handleProceed}
            disabled={selectedSeats.length === 0}
            style={{ 
              opacity: selectedSeats.length === 0 ? 0.5 : 1,
              cursor: selectedSeats.length === 0 ? 'not-allowed' : 'pointer'
            }}
          >
            Proceed to Booking
          </button>
        </div>
      </div>
    </div>
  );
};

export default SeatSelection;
